import math  # included in case math operations are needed, though not strictly required here

def solve(weight_kg):
    # Step 1: compute_maintenance_fluid_rate
    # Calculate maintenance fluid rate in mL/hr using weight-based segmented formulas
    if weight_kg <= 10:
        maintenance_fluid_rate = 4.0 * weight_kg
    elif weight_kg <= 20:
        maintenance_fluid_rate = 40.0 + 2.0 * (weight_kg - 10)
    else:
        maintenance_fluid_rate = 60.0 + 1.0 * (weight_kg - 20)

    yield {
        "step_name": "compute_maintenance_fluid_rate",
        "step_description": "Calculate maintenance fluid rate in mL/hr using weight-based segmented formulas.",
        "step_result": maintenance_fluid_rate,
        "unit": "mL/hr"
    }

    # final result
    return maintenance_fluid_rate
